data.content:
**MSTest 3.x+ does have these assertions.** Here are the comparison assertions you need:

```csharp
Assert.IsGreaterThan(lowerBound, actual);   // actual > lowerBound
Assert.IsLessThan(upperBound, actual);      // actual < upperBound
Assert.IsInRange(actual, low, high);        // low <= actual <= high
```

For your `ScoreCalculator`, here's how to apply them:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_IsInRange()
    {
        var result = _calc.CalculatePercentage(3, 7);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);   // result > 0
        Assert.IsLessThan(100.0, result);    // result < 100
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_IsInRange()
    {
        var result = _calc.NormalizeScore(50.0, 200.0);

        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }
}
```

**Key points:**
- `Assert.IsInRange(actual, low, high)` — perfect for verifying normalized scores stay within bounds
- `Assert.IsGreaterThan(lowerBound, actual)` — asserts `actual > lowerBound`
- `Assert.IsLessThan(upperBound, actual)` — asserts `actual < upperBound`
- These require **MSTest 3.8+** (via `MSTest` package or `MSTest.Sdk`)

These give much better failure messages than `Assert.IsTrue(result > 0)` — on failure you'll see the actual value vs. the bound, not just "expected True, got False".
